{"expression": "// Check the main listing section in detail
const mainSection = document.querySelector('[role="main"]');
if (mainSection) {
  const allTextElements = mainSection.querySelectorAll('button, a, span, div');
  const texts = [];
  allTextElements.forEach(el => {
    if (el.textContent.trim()) texts.push(el.textContent.trim());
  });
  // Get unique texts
  [...new Set(texts)].filter(t => t.length > 2).join(' | ');
} else 'no main';
"}

